// Presentational panel for an auto-generated AI narrative. The parent owns the
// mutation (so it can build the right payload + auto-trigger); this renders the
// "Interpreting result…" status, the markdown, or an error, plus a regenerate
// affordance.
import { Markdown } from '@/components/Markdown'
import type { NarrativeResponse } from '@/types/api'

export function NarrativePanel({
  isPending,
  data,
  error,
  onRegenerate,
}: {
  isPending: boolean
  data: NarrativeResponse | undefined
  error: unknown
  onRegenerate: () => void
}) {
  return (
    <div className="rounded-md border border-primary/30 bg-primary/5 p-3">
      <div className="mb-2 flex items-center justify-between gap-2">
        <h4 className="text-sm font-medium text-primary">✦ AI interpretation</h4>
        {(data || error) && !isPending && (
          <button
            type="button"
            onClick={onRegenerate}
            className="text-[11px] text-muted-foreground hover:text-primary"
          >
            ↻ regenerate
          </button>
        )}
      </div>
      {isPending ? (
        <div className="flex items-center gap-2 text-sm text-muted-foreground">
          <span className="inline-block h-3.5 w-3.5 animate-spin rounded-full border-2 border-primary/40 border-t-primary" />
          Interpreting result…
        </div>
      ) : error ? (
        <p className="text-xs text-destructive">Interpretation unavailable: {String(error)}</p>
      ) : data ? (
        <>
          <Markdown>{data.narrative}</Markdown>
          <p className="mt-2 rounded border border-yellow-400/50 bg-yellow-400/10 px-2 py-1 text-[11px] font-bold text-yellow-300">
            NOTE: Generated by {data.model}. AI-generated — verify against the data.
          </p>
        </>
      ) : null}
    </div>
  )
}
